## Task 3: `analyzeStack` — full per-unit verdict

**Files:**

- Modify: `src/commands/stack-analysis.ts`
- Test: `tests/commands/stack-analysis.test.ts`

The verdict combines: `missingId` (from `missingIdHashes` restricted to the unit's commits), `unpushed` (`unit.commits.at(-1)` vs `rev-parse refs/remotes/origin/<branch>`), `misTargeted` (`prCache[unit.id].baseRefName` vs `expectedBaseFor`), and carries `currentBase`/`expectedBase`. The unpushed check uses a helper that returns the origin SHA or `null` when the ref does not resolve.

- [ ] **Step 1: Write the failing test — a pushed, correctly-targeted unit has no flags**

Append inside the `describe`:

```ts
async function commitAndPush(
  git: ReturnType<typeof createRealGitRunner>,
  repo: TestRepo,
  subject: string,
  id: string | null,
  push: boolean,
): Promise<string> {
  const msg = id ? `${subject}\n\nSpry-Commit-Id: ${id}` : subject;
  await git.run(["commit", "--allow-empty", "-m", msg], { cwd: repo.path });
  const head = (await git.run(["rev-parse", "HEAD"], { cwd: repo.path })).stdout.trim();
  if (push && id) {
    await git.run(["push", "origin", `${head}:refs/heads/spry/test/${id}`], { cwd: repo.path });
    await git.run(["fetch", "origin"], { cwd: repo.path });
  }
  return head;
}

function unit(id: string, tip: string): PRUnit {
  return { type: "single", id, title: undefined, commitIds: [id], commits: [tip], subjects: [id] };
}

test("pushed + correctly-targeted bottom unit → no flags", async () => {
  const repo = await makeRepo();
  const git = createRealGitRunner();
  const ctx = { git: { run: (a: string[], o?: any) => git.run(a, { ...o, cwd: repo.path }) } };
  await git.run(["checkout", "-b", "feature"], { cwd: repo.path });
  const tip = await commitAndPush(git, repo, "Add login", "aaa11111", true);

  const u = unit("aaa11111", tip);
  const prCache: PRCache = {
    aaa11111: {
      number: 1, url: "u", state: "OPEN", title: "T", baseRefName: "main",
      checksStatus: "passing", reviewDecision: "none",
      reviewThreads: { resolved: 0, total: 0 },
      branch: "spry/test/aaa11111", cachedAt: "now",
    },
  };
  const analysis = await analyzeStack(ctx as any, {
    units: [u],
    commits: [{ hash: tip, subject: "Add login", body: "", trailers: { "Spry-Commit-Id": "aaa11111" } }],
    prCache,
    config: cfg(),
  });
  const a = analysis.units[0]!;
  expect(a.missingId).toBe(false);
  expect(a.unpushed).toBe(false);
  expect(a.misTargeted).toBe(false);
  expect(a.expectedBase).toBe("main");
});
```

- [ ] **Step 2: Run test to verify it fails**

Run: `bun test tests/commands/stack-analysis.test.ts -t "no flags"`
Expected: FAIL — stub returns `{ units: [] }`, so `analysis.units[0]` is undefined.

- [ ] **Step 3: Implement the full `analyzeStack`**

Replace the stub body in `src/commands/stack-analysis.ts`:

```ts
async function originSha(
  git: GitRunner,
  branch: string,
  cwd: string | undefined,
): Promise<string | null> {
  const res = await git.run(["rev-parse", "--verify", "--quiet", `refs/remotes/origin/${branch}`], {
    cwd,
  });
  if (res.exitCode !== 0) return null;
  const sha = res.stdout.trim();
  return sha.length > 0 ? sha : null;
}

export async function analyzeStack(
  ctx: { git: GitRunner },
  input: AnalyzeStackInput,
  opts: AnalyzeStackOptions = {},
): Promise<StackAnalysis> {
  const { units, commits, prCache, config } = input;
  const cwd = opts.cwd;
  const missing = new Set(missingIdHashes(commits));

  const analyzed: UnitAnalysis[] = [];
  for (const unit of units) {
    const branch = branchForUnit(unit, config);
    const localTip = unit.commits.at(-1);
    const remoteTip = await originSha(ctx.git, branch, cwd);
    const unpushed = !localTip || remoteTip === null || remoteTip !== localTip;

    const missingId = unit.commits.some((sha) => missing.has(sha));

    const cached = prCache[unit.id];
    const currentBase = cached?.baseRefName;
    const expectedBase = expectedBaseFor(unit, units, config);
    const misTargeted = cached !== undefined && cached.baseRefName !== expectedBase;

    analyzed.push({ unit, branch, missingId, unpushed, misTargeted, currentBase, expectedBase });
  }
  return { units: analyzed };
}
```

Note: `unit.commits` are the unit's SHAs; `missingIdHashes` keys on `commits[].hash`, so `missingId` is true when any of the unit's SHAs is in the missing set. The `commits` input must therefore carry the same SHAs the units reference (the caller passes the parsed stack commits — see Task 5).

