      { hash: t2, subject: "y", body: "", trailers: { "Spry-Commit-Id": "bbb22222" } },
    ],
    prCache,
    config: cfg(),
  });
  const upper = analysis.units.find((u) => u.unit.id === "bbb22222")!;
  expect(upper.misTargeted).toBe(true);
  expect(upper.expectedBase).toBe("spry/test/aaa11111");
});
```

