  await git.run(["commit", "--allow-empty", "-m", "A\n\nSpry-Commit-Id: aaa11111"], { cwd: repo.path });
  const head = (await git.run(["rev-parse", "HEAD"], { cwd: repo.path })).stdout.trim();
  await git.run(["push", "origin", `${head}:refs/heads/spry/test/aaa11111`], { cwd: repo.path });

  const { gh, calls } = stubGh(ghPRMap({ "spry/test/aaa11111": { number: 1, baseRefName: "main" } }));
