function ghPRMapLand(
  m: Record<string, { number: number; baseRefName: string; checksStatus?: string; reviewDecision?: string | null }>,
) {
  return (call: StubGhCall): CommandResult => {
    if (call.args[0] !== "api" || call.args[1] !== "graphql")
      return { stdout: "", stderr: `unexpected: ${call.args.join(" ")}`, exitCode: 1 };
    const branch = call.args.find((a) => a.startsWith("branch="))?.slice("branch=".length) ?? "";
    const pr = m[branch];
    const nodes = pr
      ? [{
          number: pr.number, url: `https://x/pull/${pr.number}`, state: "OPEN", title: "T",
          baseRefName: pr.baseRefName, reviewDecision: pr.reviewDecision ?? null,
          reviewThreads: { totalCount: 0, nodes: [] },
          commits: { nodes: [{ commit: { statusCheckRollup: pr.checksStatus
            ? { contexts: { nodes: [{ __typename: "CheckRun", status: "COMPLETED", conclusion: pr.checksStatus === "PASSING" ? "SUCCESS" : "FAILURE" }] } }
            : null } }] },
        }]
      : [];
    return { stdout: JSON.stringify({ data: { repository: { pullRequests: { nodes } } } }), stderr: "", exitCode: 0 };
  };
}
